def lucide_icon(name: str, size: int = 16, color: str = "currentColor", stroke_width: float = 2.0) -> str:
    """Retorna HTML de ícone Lucide como SVG inline.
    Todos os atributos de apresentação vão no style para sobreviver ao DOMPurify do Streamlit.
    """
    paths = LUCIDE_ICONS.get(name, "")
    if not paths:
        return ""
    style = (
        f"display:inline-block;vertical-align:middle;flex-shrink:0;"
        f"fill:none;stroke:{color};stroke-width:{stroke_width};"
        f"stroke-linecap:round;stroke-linejoin:round;"
    )
    return (
        f'<svg xmlns="http://www.w3.org/2000/svg" width="{size}" height="{size}" '
        f'viewBox="0 0 24 24" style="{style}">'
        f'{paths}</svg>'
    )
